import { RarityBadge } from './RarityBadge'
import { CardGenerator } from '@/lib/card-generator'

interface CardProps {
  name: string
  description: string
  attack: number
  defense: number
  range: number
  rarity: string
  type: string
  imageUrl?: string
}

export function Card({ name, description, attack, defense, range, rarity, type, imageUrl }: CardProps) {
  const rarityColor = CardGenerator.getRarityColor(rarity)
  const typeIcon = CardGenerator.getTypeIcon(type)
  const rarityEmoji = CardGenerator.getRarityEmoji(rarity)

  return (
    <div className="bg-white rounded-lg shadow-lg overflow-hidden transform hover:scale-105 transition-transform duration-200">
      {/* Card Header */}
      <div className={`p-4 ${rarityColor} text-white`}>
        <div className="flex items-center justify-between mb-2">
          <h3 className="text-xl font-bold text-white">{name}</h3>
          <div className="text-2xl">{typeIcon}</div>
        </div>
        <div className="flex items-center gap-2">
          <RarityBadge rarity={rarity} />
          <span className="text-sm bg-white/20 px-2 py-1 rounded">{type}</span>
        </div>
      </div>

      {/* Card Art */}
      <div className="w-full h-64 bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center overflow-hidden">
        {imageUrl ? (
          <img 
            src={imageUrl} 
            alt={`${name} card art`}
            className="w-full h-full object-cover"
            onError={(e) => {
              const target = e.target as HTMLImageElement;
              target.style.display = 'none';
              const fallback = target.parentElement?.querySelector('.fallback-art');
              if (fallback) fallback.classList.remove('hidden');
            }}
          />
        ) : (
          <div className="fallback-art hidden text-6xl opacity-50">🎴</div>
        )}
      </div>

      {/* Card Stats */}
      <div className="p-4 bg-gray-50">
        <div className="grid grid-cols-3 gap-2 text-center mb-3">
          <div className="bg-red-100 rounded p-2">
            <div className="text-sm text-red-600 font-semibold">Attack</div>
            <div className="text-xl font-bold text-red-700">{attack}</div>
          </div>
          <div className="bg-blue-100 rounded p-2">
            <div className="text-sm text-blue-600 font-semibold">Defense</div>
            <div className="text-xl font-bold text-blue-700">{defense}</div>
          </div>
          <div className="bg-green-100 rounded p-2">
            <div className="text-sm text-green-600 font-semibold">Range</div>
            <div className="text-xl font-bold text-green-700">{range}</div>
          </div>
        </div>

        {/* Card Description */}
        <p className="text-sm text-gray-600 text-center">
          {description}
        </p>
      </div>
    </div>
  )
}